import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import API from '../api';
import BottomNav from '../components/BottomNav';

export default function ListingDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [listing, setListing] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get(`/listings/${id}`).then(r => { setListing(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="page" style={{ textAlign: 'center', padding: 40 }}>Loading...</div>;
  if (!listing) return <div className="page">Óª¬Óª¥ÓªôÓª»Óª╝Óª¥ Óª»Óª¥Óª»Óª╝Óª¿Óª┐</div>;

  return (
    <div>
      <div className="page">
        <button onClick={() => navigate(-1)} style={{ background: 'none', border: 'none', fontSize: 20, cursor: 'pointer', marginBottom: 12 }}>ÔåÉ Óª½Óª┐Óª░Óºç Óª»Óª¥Óªô</button>
        <div style={{ background: 'linear-gradient(135deg,#6C63FF,#764ba2)', borderRadius: 16, height: 160, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 60, marginBottom: 16 }}>­ƒÅá</div>
        <h2 style={{ fontWeight: 700, marginBottom: 8 }}>{listing.title}</h2>
        <p style={{ color: '#718096', marginBottom: 12 }}>­ƒôì {listing.area}</p>
        <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
          <span className={`badge badge-${listing.type}`}>{listing.type}</span>
          <span className={`badge badge-${listing.gender}`}>{listing.gender}</span>
        </div>
        <div className="card">
          <h3 style={{ marginBottom: 8 }}>Óª¼Óª┐Óª¼Óª░Óªú</h3>
          <p style={{ color: '#718096' }}>{listing.description}</p>
        </div>
        <div className="card">
          <h3 style={{ marginBottom: 8 }}>Óª©ÓºüÓª¼Óª┐ÓªºÓª¥</h3>
          <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
            {listing.amenities?.map(a => <span key={a} className="tag">{a}</span>)}
          </div>
        </div>
        {listing.owner && (
          <div className="card">
            <h3 style={{ marginBottom: 8 }}>Óª»ÓºïÓªùÓª¥Óª»ÓºïÓªù</h3>
            <p style={{ color: '#718096' }}>­ƒæñ {listing.owner.name}</p>
            <p style={{ color: '#718096' }}>­ƒô× {listing.owner.phone}</p>
          </div>
        )}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'white', borderRadius: 14, padding: 16, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
          <div>
            <div style={{ fontWeight: 700, fontSize: 22, color: '#6C63FF' }}>Óº│{listing.rent?.toLocaleString()}</div>
            <div style={{ fontSize: 12, color: '#718096' }}>Óª¬ÓºìÓª░ÓªñÓª┐ Óª«Óª¥Óª©</div>
          </div>
          <button className="btn btn-primary" onClick={() => navigate('/chat')}>­ƒÆ¼ Óª«ÓºçÓª©ÓºçÓª£ ÓªòÓª░Óºï</button>
        </div>
      </div>
      <BottomNav />
    </div>
  );
}
